// frontend/src/services/dashboardService.js
import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

// Configurar axios para incluir cookies nas requisições
axios.defaults.withCredentials = true;

class DashboardService {
  async getUserStats() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/stats`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getOpenTrades() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/trades/open`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getClosedTrades(filters = {}) {
    try {
      const params = new URLSearchParams();

      if (filters.start_date) {
        params.append('start_date', filters.start_date);
      }

      if (filters.end_date) {
        params.append('end_date', filters.end_date);
      }

      if (filters.limit) {
        params.append('limit', filters.limit);
      }

      const url = `${API_BASE_URL}/api/dashboard/trades/closed${params.toString() ? '?' + params.toString() : ''}`;
      console.log('🌐 DashboardService: Fazendo request para:', url);
      const response = await axios.get(url);
      console.log('📡 DashboardService: Resposta raw do backend:', response.data);

      // Validar a resposta
      if (!response.data || !response.data.success) {
        console.error('❌ DashboardService: Dados inválidos:', response.data);
        throw new Error('Dados de trades inválidos ou não encontrados');
      }

      // A resposta do backend retorna os trades em 'data', não 'trades'
      const trades = response.data.data || [];
      console.log('✅ DashboardService: Trades extraídos:', trades);
      console.log('📊 DashboardService: Total encontrado:', trades.length);

      // Garantir que trades é um array
      if (!Array.isArray(trades)) {
        console.warn('⚠️ DashboardService: Trades não é array, retornando vazio');
        return { trades: [], filters: response.data.filters || {} };
      }

      const result = { trades, filters: response.data.filters || {} };
      console.log('🎯 DashboardService: Resultado final:', result);
      return result;
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
      if (error.response?.status === 401) {
        throw new Error('Sessão expirada. Por favor, faça login novamente.');
      }
      throw error.response?.data || { message: 'Erro ao carregar operações encerradas' };
    }
  }

  async getProfitCurve() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/profit-curve`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getProfitCurveData() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/profit-curve`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async syncTrades() {
    try {
      const response = await axios.post(`${API_BASE_URL}/api/dashboard/sync-trades`);

      // Validar a resposta
      if (!response.data) {
        throw new Error('Resposta inválida do servidor');
      }

      // Verificar se há mensagem de erro específica
      if (response.data.error) {
        throw new Error(response.data.error);
      }

      return response.data;
    } catch (error) {
      console.error('Erro ao sincronizar trades:', error);
      if (error.response?.status === 401) {
        throw new Error('Sessão expirada. Por favor, faça login novamente.');
      } else if (error.response?.status === 400) {
        throw new Error('Credenciais da API não configuradas ou inválidas.');
      }
      throw error.response?.data || { message: 'Erro ao sincronizar trades' };
    }
  }

  async startAutoSync() {
    try {
      const response = await axios.post(`${API_BASE_URL}/api/dashboard/auto-sync/start`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async stopAutoSync() {
    try {
      const response = await axios.post(`${API_BASE_URL}/api/dashboard/auto-sync/stop`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getAutoSyncStatus() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/auto-sync/status`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getAccountBalance() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/account-balance`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async getOpenPositions() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/open-positions`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  async closePosition(symbol, side) {
    try {
      const response = await axios.post(`${API_BASE_URL}/api/dashboard/close-position`, {
        symbol,
        side
      });
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  // Utilitários para formatação
  formatCurrency(value, currency = 'USDT') {
    if (value === null || value === undefined) return '0.00';
    const numValue = parseFloat(value);
    // Para valores muito pequenos (< 0.01), usar mais casas decimais
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `${numValue.toFixed(8)} ${currency}`;
    }
    // Para valores pequenos (< 1), usar 6 casas decimais para mostrar precisão
    if (Math.abs(numValue) < 1) {
      return `${numValue.toFixed(6)} ${currency}`;
    }
    // Para valores maiores, usar 4 casas decimais para manter precisão
    return `${numValue.toFixed(4)} ${currency}`;
  }

  formatPercentage(value) {
    if (value === null || value === undefined) return '0.00%';
    // Usar mais casas decimais para percentuais pequenos
    const decimals = Math.abs(value) < 1 ? 4 : 2;
    const formatted = parseFloat(value).toFixed(decimals);
    return `${formatted >= 0 ? '+' : ''}${formatted}%`;
  }

  formatNumber(value, decimals = 2) {
    if (value === null || value === undefined) return '0.00';
    return parseFloat(value).toFixed(decimals);
  }

  getColorByValue(value) {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  }

  // Formatação de data
  formatDate(dateString) {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }

  formatDateShort(dateString) {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: '2-digit'
    });
  }

  // Cálculos de trading
  calculateWinRate(trades) {
    if (!trades || trades.length === 0) return 0;
    const winningTrades = trades.filter(trade => (trade.pnl || 0) > 0);
    return (winningTrades.length / trades.length) * 100;
  }

  calculateTotalPnL(trades) {
    if (!trades || trades.length === 0) return 0;
    return trades.reduce((total, trade) => total + (trade.pnl || 0), 0);
  }

  calculateAverageROE(trades) {
    if (!trades || trades.length === 0) return 0;
    const totalROE = trades.reduce((total, trade) => total + (trade.roe || 0), 0);
    return totalROE / trades.length;
  }

  // WebSocket para dados em tempo real (placeholder)
  connectWebSocket(onMessage) {
    // Implementação futura do WebSocket
    console.log('WebSocket connection placeholder');
  }

  disconnectWebSocket() {
    // Implementação futura do WebSocket
    console.log('WebSocket disconnection placeholder');
  }

  async getApiStatus() {
    try {
      const response = await axios.get(`${API_BASE_URL}/api/dashboard/api-status`);
      return response.data;
    } catch (error) {
      throw error.response?.data || { message: 'Erro de conexão' };
    }
  }

  // Sincronizar trades fechados
  async syncClosedTrades() {
    try {
      const response = await axios.post(`${API_BASE_URL}/api/dashboard/sync-closed-trades`);
      return response.data;
    } catch (error) {
      throw new Error(error.response?.data?.message || 'Erro ao sincronizar trades fechados');
    }
  }
}

// Objeto que contém todos os métodos do serviço
const dashboardService = new DashboardService();

export default dashboardService;
